from functools import lru_cache

class Solution:

    def solve(self, n: int) -> int:

        @lru_cache(None)
        def backtrack(row, idx, path):
            if idx == n:
                res.append(tuple(row))
                return
            for i in range(n - row[idx] - 1, -1, -1):
                if (row[idx - 1] == row[idx] + i or row[idx + 1] == row[idx] + i or i == row[idx - 1] - row[idx] or i == row[idx + 1] - row[idx] or i == row[idx] - row[idx - 1] or i == row[idx] - row[idx + 1]):
                    continue
                row[idx] = i
                backtrack(row, idx + 1, path)
            return
        res = []
        backtrack([0] * n, 0, [])
        return len(res)


