#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int solve(vector<int>& nums) {
        int n = nums.size();
        int cnt = 0;
        vector<vector<int>> res;

        function<void(int, int, int*)> backtrack =
        [&] (int row, int col, int* cur) {
            if (row == n) {
                res.push_back(vector<int>(cur, cur + n));
                return;
            }
            if (col == n) {
                backtrack(row + 1, 0, cur);
                return;
            }
            if (cur[col] < col && cur[col + (row - col)] < col) {
                cur[col] += 1;
                cur[col + (n - col)] += 1;
                backtrack(row, col + 1, cur);
                cur[col] -= 1;
                cur[col + (n - col)] -= 1;
            }
            backtrack(row, col + 1, cur);
            return;
        };

        int* cur = new int[n];
        for (int i = 0; i < n; ++i) cur[i] = 0;
        backtrack(0, 0, cur);
        delete[] cur;
        return res.size();
    }
};

int main() {
    int n;
    cin >> n;
    Solution sol;
    cout << sol.solve(n) << endl;
    return 0;
}
